  1→import { lazy, Suspense, useState, useEffect, useCallback } from 'react';
  2→import { ProjectProvider, useProject } from './ProjectProvider';
  3→import { EditorProvider, useEditor } from './EditorProvider';
  4→import SvgCanvas from '@/renderers/SvgCanvas';
  5→import SheetCanvas from '@/renderers/SheetCanvas';
  6→import Toolbar from '@/ui/Toolbar';
  7→import Sidebar from '@/ui/Sidebar';
  8→import PropertiesPanel from '@/ui/PropertiesPanel';
  9→import Modal from '@/ui/Modal';
 10→import { createProject } from '@/domain/models';
 11→import { saveProject, loadProject, listProjects, deleteProject } from '@/persistence/storage';
 12→import { useAutosave } from '@/persistence/useAutosave';
 13→import { isTypingTarget } from '@/utils/keyboard';
 14→import styles from './App.module.css';
 15→
 16→const ThreePreviewPanel = lazy(() => import('@/three/viewer/ThreePreviewPanel'));
 17→
 18→function EditorShell({
 19→  project,
 20→  handleNew,
 21→  handleSave,
 22→  handleLoadClick,
 23→  isSidebarCollapsed,
 24→  isPropertiesCollapsed,
 25→  onToggleSidebar,
 26→  onToggleProperties,
 27→}) {
 28→  const {
 29→    workspaceMode,
 30→    activeSheetId,
 31→    activeFloorId,
 32→    dispatch: editorDispatch,
 33→  } = useEditor();
 34→
 35→  useEffect(() => {
 36→    const sheets = project.sheets || [];
 37→    if (!sheets.length) {
 38→      if (activeSheetId !== null) {
 39→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
 40→      }
 41→      if (workspaceMode === 'sheet') {
 42→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 43→      }
 44→      return;
 45→    }
 46→
 47→    if (!activeSheetId || !sheets.some((sheet) => sheet.id === activeSheetId)) {
 48→      editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheets[0].id });
 49→    }
 50→  }, [activeSheetId, editorDispatch, project.sheets, workspaceMode]);
 51→
 52→  return (
 53→    <div
 54→      className={styles.layout}
 55→      style={{
 56→        '--layout-sidebar-width': isSidebarCollapsed ? '0px' : 'var(--sidebar-width)',
 57→        '--layout-properties-width': isPropertiesCollapsed ? '0px' : 'var(--properties-width)',
 58→      }}
 59→    >
 60→      <div className={styles.toolbar}>
 61→        <Toolbar
 62→          onNew={handleNew}
 63→          onSave={handleSave}
 64→          onLoad={handleLoadClick}
 65→          isSidebarCollapsed={isSidebarCollapsed}
 66→          isPropertiesCollapsed={isPropertiesCollapsed}
 67→          onToggleSidebar={onToggleSidebar}
 68→          onToggleProperties={onToggleProperties}
 69→        />
 70→      </div>
 71→      <div className={`${styles.sidebar} ${isSidebarCollapsed ? styles.panelHidden : ''}`}>
 72→        <Sidebar />
 73→      </div>
 74→      <div className={styles.canvas}>
 75→        {workspaceMode === 'sheet' ? (
 76→          <SheetCanvas />
 77→        ) : (
 78→          <div className={styles.modelWorkspace}>
 79→            <div className={styles.primaryCanvas}>
 80→              <SvgCanvas />
 81→            </div>
 82→            <div className={styles.preview}>
 83→              <Suspense fallback={<div className={styles.previewFallback}>Loading 3D preview...</div>}>
 84→                <ThreePreviewPanel
 85→                  project={project}
 86→                  activeFloorId={activeFloorId}
 87→                />
 88→              </Suspense>
 89→            </div>
 90→          </div>
 91→        )}
 92→      </div>
 93→      <div className={`${styles.properties} ${isPropertiesCollapsed ? styles.panelHidden : ''}`}>
 94→        <PropertiesPanel />
 95→      </div>
 96→    </div>
 97→  );
 98→}
 99→
100→function AppInner() {
101→  const { project, isDirty, dispatch } = useProject();
102→  const [showLoadModal, setShowLoadModal] = useState(false);
103→  const [savedProjects, setSavedProjects] = useState([]);
104→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
105→  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
106→
107→  useAutosave(project, isDirty, dispatch);
108→
109→  // beforeunload warning
110→  useEffect(() => {
111→    const handler = (e) => {
112→      if (isDirty) {
113→        e.preventDefault();
114→        e.returnValue = '';
115→      }
116→    };
117→    window.addEventListener('beforeunload', handler);
118→    return () => window.removeEventListener('beforeunload', handler);
119→  }, [isDirty]);
120→
121→  const handleNew = useCallback(() => {
122→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
123→    dispatch({ type: 'PROJECT_NEW', project: createProject() });
124→  }, [isDirty, dispatch]);
125→
126→  const handleSave = useCallback(async () => {
127→    await saveProject(project);
128→    dispatch({ type: 'MARK_SAVED' });
129→  }, [project, dispatch]);
130→
131→  // Ctrl+S save
132→  useEffect(() => {
133→    const handler = (e) => {
134→      if (isTypingTarget(e.target)) return;
135→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
136→        e.preventDefault();
137→        handleSave();
138→      }
139→    };
140→    window.addEventListener('keydown', handler);
141→    return () => window.removeEventListener('keydown', handler);
142→  }, [handleSave]);
143→
144→  const handleLoadClick = useCallback(async () => {
145→    setSavedProjects(await listProjects());
146→    setShowLoadModal(true);
147→  }, []);
148→
149→  const handleLoad = useCallback(async (id) => {
150→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
151→    try {
152→      const { project: loaded, savedAt } = await loadProject(id);
153→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
154→      setShowLoadModal(false);
155→    } catch (err) {
156→      alert('Failed to load project: ' + err.message);
157→    }
158→  }, [isDirty, dispatch]);
159→
160→  const handleDelete = useCallback(async (id, name) => {
161→    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
162→    if (!confirmed) return;
163→
164→    try {
165→      await deleteProject(id);
166→      setSavedProjects(projects => projects.filter(project => project.id !== id));
167→    } catch (err) {
168→      alert('Failed to delete project: ' + err.message);
169→    }
170→  }, []);
171→
172→  const activeFloorId = project.floors[0]?.id;
173→
174→  return (
175→    <EditorProvider activeFloorId={activeFloorId}>
176→      <EditorShell
177→        project={project}
178→        handleNew={handleNew}
179→        handleSave={handleSave}
180→        handleLoadClick={handleLoadClick}
181→        isSidebarCollapsed={isSidebarCollapsed}
182→        isPropertiesCollapsed={isPropertiesCollapsed}
183→        onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
184→        onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
185→      />
186→
187→      {showLoadModal && (
188→        <Modal title="Load Project" onClose={() => setShowLoadModal(false)}>
189→          {savedProjects.length === 0 ? (
190→            <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px' }}>
191→              No saved projects found.
192→            </p>
193→          ) : (
194→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
195→              {savedProjects.map(p => (
196→                <div
197→                  key={p.id}
198→                  style={{
199→                    display: 'flex',
200→                    justifyContent: 'space-between',
201→                    alignItems: 'center',
202→                    padding: '10px 12px',
203→                    border: '1px solid var(--color-border)',
204→                    borderRadius: 'var(--radius-md)',
205→                    background: 'var(--color-surface-elevated)',
206→                    fontSize: '13px',
207→                  }}
208→                >
209→                  <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
210→                    <span style={{ fontWeight: 500 }}>{p.name}</span>
211→                    <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
212→                      {new Date(p.savedAt).toLocaleDateString()}
213→                    </span>
214→                  </div>
215→                  <div style={{ display: 'flex', gap: '8px' }}>
216→                    <button
217→                      onClick={() => handleLoad(p.id)}
218→                      style={{
219→                        padding: '6px 12px',
220→                        border: '1px solid var(--color-border)',
221→                        borderRadius: 'var(--radius-sm)',
222→                        cursor: 'pointer',
223→                        background: 'var(--color-surface-elevated)',
224→                        fontSize: '12px',
225→                        fontWeight: 500,
226→                      }}
227→                    >
228→                      Load
229→                    </button>
230→                    <button
231→                      onClick={() => handleDelete(p.id, p.name)}
232→                      style={{
233→                        padding: '6px 12px',
234→                        border: '1px solid var(--color-danger-subtle)',
235→                        borderRadius: 'var(--radius-sm)',
236→                        cursor: 'pointer',
237→                        background: 'var(--color-danger-subtle)',
238→                        color: 'var(--color-danger)',
239→                        fontSize: '12px',
240→                      }}
241→                    >
242→                      Delete
243→                    </button>
244→                  </div>
245→                </div>
246→              ))}
247→            </div>
248→          )}
249→          <button
250→            onClick={() => setShowLoadModal(false)}
251→            style={{
252→              marginTop: '16px',
253→              padding: '8px 16px',
254→              border: '1px solid var(--color-border)',
255→              borderRadius: 'var(--radius-sm)',
256→              cursor: 'pointer',
257→              fontSize: '13px',
258→              fontWeight: 500,
259→              background: 'var(--color-surface-elevated)',
260→            }}
261→          >
262→            Cancel
263→          </button>
264→        </Modal>
265→      )}
266→    </EditorProvider>
267→  );
268→}
269→
270→export default function App() {
271→  return (
272→    <ProjectProvider>
273→      <AppInner />
274→    </ProjectProvider>
275→  );
276→}
