 1→import { generateId } from './ids';
 2→
 3→export function createSheet(title = 'Sheet 1', options = {}) {
 4→  return {
 5→    id: generateId('sheet'),
 6→    title,
 7→    paperSize: options.paperSize ?? 'A3_LANDSCAPE',
 8→    scaleLabel: options.scaleLabel ?? '1:100',
 9→    drawingName: options.drawingName ?? title,
10→    projectNameOverride: options.projectNameOverride ?? '',
11→    viewports: (options.viewports || []).map((viewport) => ({ ...viewport })),
12→  };
13→}
14→
15→export function createSheetViewport(sourceView = 'plan', sourceFloorId = null, options = {}) {
16→  return {
17→    id: generateId('viewport'),
18→    sourceView,
19→    sourceFloorId,
20→    sourceRefId: options.sourceRefId ?? null,
21→    x: options.x ?? 20,
22→    y: options.y ?? 20,
23→    width: options.width ?? 160,
24→    height: options.height ?? 100,
25→    scale: options.scale ?? 100,
26→    title: options.title ?? '',
27→  };
28→}
