 74→export default function Toolbar({
 75→  onNew,
 76→  onSave,
 77→  onLoad,
 78→  isSidebarCollapsed,
 79→  isPropertiesCollapsed,
 80→  onToggleSidebar,
 81→  onToggleProperties,
 82→}) {
 83→  const { activeTool, showGrid, snapEnabled, activeFloorId, viewMode, workspaceMode, dispatch: editorDispatch } = useEditor();
 84→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 85→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan';
 86→
 87→  const [toolMenuOpen, setToolMenuOpen] = useState(false);
 88→  const toolMenuRef = useRef(null);
 89→  const setTool = (tool) => editorDispatch({ type: 'SET_TOOL', tool });
 90→
 91→  const toolItems = [
 92→    { tool: TOOLS.SELECT, label: 'Select', shortcut: 'V' },
 93→    { tool: TOOLS.DIMENSION, label: 'Dim', shortcut: 'M' },
 94→    { tool: TOOLS.WALL, label: 'Wall', shortcut: 'W' },
 95→    { tool: TOOLS.BEAM, label: 'Beam', shortcut: 'B' },
 96→    { tool: TOOLS.STAIR, label: 'Stair', shortcut: 'T' },
 97→    { tool: TOOLS.SECTION, label: 'Section', shortcut: 'Q' },
 98→    { tool: TOOLS.SLAB, label: 'Slab', shortcut: 'S' },
 99→    { tool: TOOLS.ROOM, label: 'Room', shortcut: 'R' },
100→    { tool: TOOLS.DOOR, label: 'Door', shortcut: 'D', hint: 'F to flip swing' },
101→    { tool: TOOLS.WINDOW, label: 'Window', shortcut: 'N' },
102→    { tool: TOOLS.COLUMN, label: 'Column', shortcut: 'C' },
103→  ];
104→  const activeToolLabel = toolItems.find(t => t.tool === activeTool)?.label || 'Tools';
105→  const handleUndo = useCallback(() => {
106→    if (!canUndo) return;
107→    dispatch({ type: 'UNDO' });
108→    editorDispatch({ type: 'DESELECT' });
109→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Undid last change.' });
110→  }, [canUndo, dispatch, editorDispatch]);
111→  const handleRedo = useCallback(() => {
112→    if (!canRedo) return;
113→    dispatch({ type: 'REDO' });
114→    editorDispatch({ type: 'DESELECT' });
115→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
116→  }, [canRedo, dispatch, editorDispatch]);
117→
118→  const handleDetectRooms = () => {
119→    const floor = project.floors.find(f => f.id === activeFloorId);
120→    if (!floor || floor.walls.length < 3) {
121→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
122→      return;
123→    }
124→
125→    const detected = detectRooms(floor.walls, floor.columns || []);
126→    const rooms = detected.map((d, i) => createRoom(`Room ${i + 1}`, d.points));
127→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
128→    editorDispatch({ type: 'DESELECT' });
129→    editorDispatch({
130→      type: 'SET_STATUS_MESSAGE',
131→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
132→    });
133→  };
134→
135→  useEffect(() => {
136→    const handleKeyDown = (e) => {
137→      if (!(e.ctrlKey || e.metaKey)) return;
138→      if (isTypingTarget(e.target)) return;
139→
140→      const key = e.key.toLowerCase();
141→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
142→      const isUndo = key === 'z' && !e.shiftKey;
143→      if (!isUndo && !isRedo) return;
144→
145→      e.preventDefault();
146→      if (isRedo) {
147→        handleRedo();
148→        return;
149→      }
150→      handleUndo();
151→    };
152→
153→    window.addEventListener('keydown', handleKeyDown);
154→    return () => window.removeEventListener('keydown', handleKeyDown);
155→  }, [handleRedo, handleUndo]);
156→
157→  useEffect(() => {
158→    if (!toolMenuOpen) return;
159→    const handleClickOutside = (e) => {
160→      if (toolMenuRef.current && !toolMenuRef.current.contains(e.target)) {
161→        setToolMenuOpen(false);
162→      }
163→    };
164→    document.addEventListener('mousedown', handleClickOutside);
165→    return () => document.removeEventListener('mousedown', handleClickOutside);
166→  }, [toolMenuOpen]);
167→
168→  return (
169→    <div className={styles.toolbar}>
170→      <div className={styles.group}>
171→        <button className={styles.btn} onClick={onNew}>New</button>
172→        <button
173→          className={`${styles.btn} ${styles.iconBtn}`}
174→          onClick={handleUndo}
175→          disabled={!canUndo}
176→          title="Undo (Ctrl/Cmd+Z)"
177→          aria-label="Undo"
178→        >
179→          <UndoIcon />
180→        </button>
181→        <button
182→          className={`${styles.btn} ${styles.iconBtn}`}
183→          onClick={handleRedo}
184→          disabled={!canRedo}
185→          title="Redo (Ctrl/Cmd+Shift+Z or Ctrl/Cmd+Y)"
186→          aria-label="Redo"
187→        >
188→          <RedoIcon />
189→        </button>
190→        <button className={styles.btn} onClick={onSave}>
191→          {isDirty && <span className={styles.dirtyIndicator} />}
192→          Save
193→        </button>
194→        <button className={styles.btn} onClick={onLoad}>Load</button>
195→      </div>
196→
197→      <div className={styles.group}>
198→        <button
199→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'plan' ? styles.active : ''}`}
